import math

class Node:
    def __init__(self, key):
        self.key = key
        self.left = None
        self.right = None

class BST:
    def __init__(self):
        self.root = None

    def insert(self, key):
        if self.root is None:
            self.root = Node(key)
        else:
            self._insert_recursive(self.root, key)

    def _insert_recursive(self, node, key):
        if key < node.key:
            if node.left is None:
                node.left = Node(key)
            else:
                self._insert_recursive(node.left, key)
        elif key > node.key:
            if node.right is None:
                node.right = Node(key)
            else:
                self._insert_recursive(node.right, key)
        # Duplicate keys are ignored in this implementation

    def delete(self, key):
        self.root = self._delete_recursive(self.root, key)

    def _delete_recursive(self, node, key):
        if node is None:
            return None

        if key < node.key:
            node.left = self._delete_recursive(node.left, key)
        elif key > node.key:
            node.right = self._delete_recursive(node.right, key)
        else:
            if node.left is None:
                return node.right
            elif node.right is None:
                return node.left

            min_larger_node = self._find_min(node.right)
            node.key = min_larger_node.key
            node.right = self._delete_recursive(node.right, min_larger_node.key)

        return node

    def _find_min(self, node):
        current = node
        while current.left:
            current = current.left
        return current

    def search(self, key):
        return self._search_recursive(self.root, key)

    def _search_recursive(self, node, key):
        if node is None or node.key == key:
            return node
        if key < node.key:
            return self._search_recursive(node.left, key)
        return self._search_recursive(node.right, key)

    def height(self):
        return self._height_recursive(self.root)

    def _height_recursive(self, node):
        if node is None:
            return -1  # Empty tree has height -1, single node has height 0
        return 1 + max(self._height_recursive(node.left), 
                       self._height_recursive(node.right))

    def is_valid_bst(self):
        return self._is_valid_recursive(self.root, -math.inf, math.inf)

    def _is_valid_recursive(self, node, min_val, max_val):
        if node is None:
            return True
        if node.key <= min_val or node.key >= max_val:
            return False
        return (self._is_valid_recursive(node.left, min_val, node.key) and
                self._is_valid_recursive(node.right, node.key, max_val))

    def floor(self, key):
        result = None
        node = self.root
        while node:
            if node.key == key:
                return node.key
            elif key < node.key:
                node = node.left
            else:
                result = node.key
                node = node.right
        return result

    def ceiling(self, key):
        result = None
        node = self.root
        while node:
            if node.key == key:
                return node.key
            elif key > node.key:
                node = node.right
            else:
                result = node.key
                node = node.left
        return result

    def range_query(self, k1, k2):
        result = []
        self._range_recursive(self.root, k1, k2, result)
        return result

    def _range_recursive(self, node, k1, k2, result):
        if node is None:
            return
        if node.key > k1:
            self._range_recursive(node.left, k1, k2, result)
        if k1 <= node.key <= k2:
            result.append(node.key)
        if node.key < k2:
            self._range_recursive(node.right, k1, k2, result)

    def inorder(self):
        result = []
        self._inorder_recursive(self.root, result)
        return result

    def _inorder_recursive(self, node, result):
        if node:
            self._inorder_recursive(node.left, result)
            result.append(node.key)
            self._inorder_recursive(node.right, result)

